sql:
SELECT traffic_incidents.incident_id, severity_levels.severity_description
FROM traffic_incidents
INNER JOIN severity_levels ON traffic_incidents.crash_severity = severity_levels.severity_id;

external_knowledge:
- "dark clouds" metaphorically refers to fatal crashes; "bustling cities" implies high traffic volume;
- "tragic toll" represents incidents with at least one injury;
- "human error" is a reference to the cause of crashes.

sql:
SELECT *
FROM traffic_incidents
WHERE roadway = 'CAMELOT DRIVE' AND city_town = 'WORCESTER';

SELECT AVG(average_daily_traffic) AS average_residential_traffic
FROM roadways
WHERE type = 'Residential';

SELECT city_name
FROM cities
WHERE population = (SELECT MAX(population) FROM cities);

SELECT agency_name, contact_number 
FROM police_agencies 
WHERE agency_type = 'state' AND jurisdiction = 'New England';

external_knowledge:
- 'perilous crossroads' metaphorically refers to intersections with the highest injury and fatality rates;
- 'shadows of harm and loss' symbolizes the impact of injuries and fatalities;
- 'whispers of injury' is a metaphor for the injury count;
- 'echoes of fatality' metaphorically represents the fatality count.
